--
-- Table structure for table `app_settings`
--

DROP TABLE IF EXISTS `app_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `app_settings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `app_name` varchar(255) NOT NULL DEFAULT 'Teramia E-Learning',
  `school_name` varchar(255) NOT NULL DEFAULT 'SMP Teramia',
  `school_logo` varchar(255) DEFAULT NULL,
  `school_favicon` varchar(255) DEFAULT NULL,
  `building_background` varchar(255) DEFAULT NULL,
  `primary_color` varchar(20) NOT NULL DEFAULT '#1D4ED8',
  `secondary_color` varchar(20) NOT NULL DEFAULT '#1E3A8A',
  `accent_color` varchar(20) NOT NULL DEFAULT '#FACC15',
  `default_locale` varchar(5) NOT NULL DEFAULT 'id',
  `supported_locales_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`supported_locales_json`)),
  `footer_text` varchar(255) DEFAULT NULL,
  `school_email` varchar(255) DEFAULT NULL,
  `school_phone` varchar(50) DEFAULT NULL,
  `school_address` text DEFAULT NULL,
  `active_academic_year_id` bigint(20) unsigned DEFAULT NULL,
  `active_semester_id` bigint(20) unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `app_settings_active_academic_year_id_foreign` (`active_academic_year_id`),
  KEY `app_settings_active_semester_id_foreign` (`active_semester_id`),
  CONSTRAINT `app_settings_active_academic_year_id_foreign` FOREIGN KEY (`active_academic_year_id`) REFERENCES `academic_years` (`id`) ON DELETE SET NULL,
  CONSTRAINT `app_settings_active_semester_id_foreign` FOREIGN KEY (`active_semester_id`) REFERENCES `semesters` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `app_settings`
--

