--
-- Table structure for table `exams`
--

DROP TABLE IF EXISTS `exams`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `exams` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `course_id` bigint(20) unsigned NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `created_by` bigint(20) unsigned NOT NULL,
  `exam_type` varchar(30) NOT NULL DEFAULT 'mixed',
  `start_at` datetime DEFAULT NULL,
  `end_at` datetime DEFAULT NULL,
  `duration_minutes` int(10) unsigned NOT NULL DEFAULT 60,
  `shuffle_questions` tinyint(1) NOT NULL DEFAULT 0,
  `shuffle_options` tinyint(1) NOT NULL DEFAULT 0,
  `auto_submit` tinyint(1) NOT NULL DEFAULT 1,
  `show_result_after_submit` tinyint(1) NOT NULL DEFAULT 0,
  `show_answer_key` tinyint(1) NOT NULL DEFAULT 0,
  `show_explanation` tinyint(1) NOT NULL DEFAULT 0,
  `max_attempts` tinyint(3) unsigned NOT NULL DEFAULT 1,
  `required_paid_month` tinyint(3) unsigned DEFAULT NULL,
  `target_score` decimal(8,2) NOT NULL DEFAULT 100.00,
  `objective_weight_percent` decimal(5,2) NOT NULL DEFAULT 60.00,
  `essay_weight_percent` decimal(5,2) NOT NULL DEFAULT 40.00,
  `status` varchar(20) NOT NULL DEFAULT 'draft',
  `is_published` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
