  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `restored_by` bigint(20) unsigned NOT NULL,
  `entity_type` varchar(100) NOT NULL,
  `entity_id` bigint(20) unsigned NOT NULL,
  `restored_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `note` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `restore_logs_restored_by_foreign` (`restored_by`),
  CONSTRAINT `restore_logs_restored_by_foreign` FOREIGN KEY (`restored_by`) REFERENCES `users` (`id`)
